SELECT p.id, p.registration_id, p.patient_id, pat.patient_name, p.payment_type, p.total_amount, p.payment_method, p.payment_time, p.status FROM payment p LEFT JOIN patient pat ON p.patient_id = pat.id
AND pat.patient_name LIKE CONCAT('%', #{patientName}, '%')
AND p.status = #{status}
ORDER BY p.payment_time DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(*) FROM payment p LEFT JOIN patient pat ON p.patient_id = pat.id
AND pat.patient_name LIKE CONCAT('%', #{patientName}, '%')
AND p.status = #{status}

SELECT * FROM payment


        AND patient_id = #{patientId}


ORDER BY payment_time DESC
LIMIT #{offset}, #{pageSize}
